use ritual_spc_verification::SpcVerifier;

let components_container = WithComponents {
    db_provider_container: WithMeteredProvider { /* ... */ },
    node_adapter,
    head,
    spc_verifier: builder_ctx.spc_verifier().clone(),
};

/// Returns the shared SPC verifier.
pub const fn spc_verifier(&self) -> &Arc<SpcVerifier<T::Provider>> {
    &self.right().spc_verifier
}

pub struct WithComponents<T, CB>
where
    T: FullNodeTypes,
    CB: NodeComponentsBuilder<T>,
{
    db_provider_container: WithMeteredProvider<NodeTypesWithDBAdapter<T::Types, T::DB>>,
    node_adapter: NodeAdapter<T, CB::Components>,
    head: Head,
    spc_verifier: Arc<SpcVerifier<T::Provider>>,
}
